/**
 * Chart.js placeholder for offline use
 *
 * To enable full charts:
 * 1. Download Chart.js (chart.umd.js or chart.min.js)
 * 2. Save it as static/js/chart.min.js (replace this file)
 *
 * This placeholder defines a minimal Chart stub so that the
 * rest of the UI can call new Chart(ctx, config) without errors.
 */

window.Chart = window.Chart || function (ctx, config) {
  console.warn('Chart.js placeholder in use. Please replace static/js/chart.min.js with the real Chart.js for full functionality.');
  return {
    update: function () {},
    destroy: function () {}
  };
};


